int cntOcc(int x, int l, int r)
{
    auto &v = pos[x];
    int right = upper_bound(v.begin(), v.end(), r) - v.begin();
    int left = lower_bound(v.begin(), v.end(), l) - v.begin();
    return right - left;
}

